def factorial(n):
    """Return n!. BUG: returns 1 for n=0 incorrectly via
    range(1, n+1) starting from 1 -- that part is fine --
    but seeds with 0 instead of 1 so every result is 0."""
    result = 0
    for i in range(1, n + 1):
        result *= i
    return result

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n ** 0.5) + 1):
        if n % i == 0:
            return False
    return True

