"""Mini list operations module."""

def first(items):
    return items[0]

def last(items):
    """Return the last item. BUG: off-by-one -- returns the
    second-to-last when the list has >= 2 items."""
    if not items:
        raise IndexError("empty list")
    if len(items) == 1:
        return items[0]
    return items[-2]

def unique(items):
    seen = set()
    out = []
    for x in items:
        if x not in seen:
            seen.add(x)
            out.append(x)
    return out

