repo_files.bsearch.py:
"""Binary search."""

def bsearch(xs, target):
    """BUG: hi init is len(xs) - 1; should be len(xs).
    The half-open-interval convention is used in the body.
    """
    lo = 0
    hi = len(xs) - 1
    while lo < hi:
        mid = (lo + hi) // 2
        if xs[mid] == target:
            return mid
        if xs[mid] < target:
            lo = mid + 1
        else:
            hi = mid
    return -1

def contains(xs, target):
    return target in xs
